            WriteLiteral(@"<script>
    function formatDate(input) {
        if (!input.value) return;

        let date = new Date(input.value);
        if (isNaN(date.getTime())) return; // Avoid invalid date errors

        let hours = date.getHours();
        let minutes = date.getMinutes().toString().padStart(2, ""0"");
        let suffix = hours < 12 ? ""Morning"" : ""Evening"";

        hours = hours % 12 || 12; // Convert to 12-hour format

        let formattedDate = date.getDate().toString().padStart(2, ""0"") + ""/"" +
                            (date.getMonth() + 1).toString().padStart(2, ""0"") + ""/"" +
                            date.getFullYear() + "" "" +
                            hours + "":"" + minutes + "" "" + suffix;

        input.value = formattedDate;
    }

    document.addEventListener(""DOMContentLoaded"", function () {
        let visitDateInput = document.getElementById(""visitDate"");
        if (visitDateInput) {
            formatDate(visitDateInput);
        }
    });
</script>



