    public string FormatVisitDate(DateTime? date)
    {
        if (!date.HasValue) return "";
        return date.Value.ToString("dd/MM/yyyy hh:mm tt")
            .Replace("AM", "Morning")
            .Replace("PM", "Evening");
    }

